defmodule SessionPlug do
  import Plug.Conn

  @session_cookie "_app_session"

  def init(opts), do: opts

  def call(conn, _opts) do
    session_cookie = conn.cookies[@session_cookie]
    
    case SessionManager.deserialize_session(session_cookie) do
      {:ok, session} ->
        conn
        |> assign(:session, session)
        |> assign(:current_user_id, session.user_id)
        |> register_before_send(&put_session_cookie/1)
      
      {:error, _reason} ->
        conn
        |> assign(:session, nil)
        |> assign(:current_user_id, nil)
        |> register_before_send(&put_session_cookie/1)
    end
  end

  defp put_session_cookie(conn) do
    case conn.assigns[:session] do
      nil -> 
        delete_resp_cookie(conn, @session_cookie)
      
      session ->
        serialized = SessionManager.serialize_session(session)
        put_resp_cookie(conn, @session_cookie, serialized, 
          http_only: true,
          secure: true,
          same_site: "Lax",
          max_age: 3600
        )
    end
  end

  def put_session(conn, user_id, data \\ %{}) do
    session = %{
      user_id: user_id,
      data: data,
      created_at: System.system_time(:second),
      expires_at: System.system_time(:second) + 3600
    }
    
    assign(conn, :session, session)
  end

  def update_session(conn, updates) do
    case conn.assigns[:session] do
      nil -> conn
      session ->
        updated_session = Map.merge(session, %{
          data: Map.merge(session.data, updates),
          expires_at: System.system_time(:second) + 3600
        })
        assign(conn, :session, updated_session)
    end
  end

  def delete_session(conn) do
    conn
    |> assign(:session, nil)
    |> assign(:current_user_id, nil)
  end

  def get_session(conn), do: conn.assigns[:session]
  
  def get_session_data(conn, key) do
    case conn.assigns[:session] do
      %{data: data} -> Map.get(data, key)
      _ -> nil
    end
  end
end

defmodule DistributedSessionStore do
  use GenServer

  def start_link(opts \\ []) do
    GenServer.start_link(__MODULE__, opts, name: __MODULE__)
  end

  def init(_opts) do
    :ets.new(:sessions, [:set, :public, :named_table, read_concurrency: true])
    {:ok, %{}}
  end

  def store_session(session_id, session_data) do
    serialized = :erlang.term_to_binary(session_data)
    :ets.insert(:sessions, {session_id, serialized, System.system_time(:second)})
    :ok
  end

  def get_session(session_id) do
    case :ets.lookup(:sessions, session_id) do
      [{^session_id, serialized, _timestamp}] ->
        {:ok, :erlang.binary_to_term(serialized, [:safe])}
      
      [] ->
        {:error, :not_found}
    end
  end

  def delete_session(session_id) do
    :ets.delete(:sessions, session_id)
    :ok
  end

  def cleanup_expired_sessions(max_age \\ 3600) do
    current_time = System.system_time(:second)
    cutoff_time = current_time - max_age
    
    :ets.select_delete(:sessions, [
      {{:_, :_, :"$1"}, [{:<, :"$1", cutoff_time}], [true]}
    ])
  end
end

defmodule SessionController do
  use Phoenix.Controller
  alias SessionPlug

  def create(conn, %{"user_id" => user_id, "data" => data}) do
    conn
    |> SessionPlug.put_session(user_id, data)
    |> json(%{status: "session_created", user_id: user_id})
  end

  def show(conn, _params) do
    case SessionPlug.get_session(conn) do
      nil ->
        conn
        |> put_status(401)
        |> json(%{error: "no_session"})
      
      session ->
        json(conn, %{session: sanitize_session(session)})
    end
  end

  def update(conn, %{"data" => data}) do
    conn
    |> SessionPlug.update_session(data)
    |> json(%{status: "session_updated"})
  end

  def delete(conn, _params) do
    conn
    |> SessionPlug.delete_session()
    |> json(%{status: "session_deleted"})
  end

  defp sanitize_session(session) do
    %{
      user_id: session.user_id,
      data: session.data,
      created_at: session.created_at,
      expires_at: session.expires_at
    }
  end
end